let allListeners = []; function filterListeners() { const search = document.getElementById('search-input').value.toLowerCase(); const type = document.getElementById('type-filter').value; const status = document.getElementById('status-filter').value; const rows = document.querySelectorAll('.listener-row'); rows.forEach(row => { const name = row.dataset.name.toLowerCase(); const t = row.dataset.type; const enabled = row.dataset.enabled === 'true'; let show = true; if (search && !name.includes(search)) show = false; if (type && t !== type) show = false; if (status === 'enabled' && !enabled) show = false; if (status === 'disabled' && enabled) show = false; row.style.display = show ? '' : 'none'; }); } function showCreateModal() { document.getElementById('modal-title').textContent = __('Create Listener'); document.getElementById('listener-id').value = ''; document.getElementById('listener-name').value = ''; document.getElementById('listener-scheme').value = 'http'; document.getElementById('listener-host').value = '0.0.0.0'; document.getElementById('listener-port').value = '8080'; document.getElementById('listener-notes').value = ''; document.getElementById('listener-enabled').checked = true; document.getElementById('listener-modal').classList.remove('hidden'); document.getElementById('listener-modal').classList.add('flex'); } function editListener(id, name, scheme, host, port, notes, enabled) { document.getElementById('modal-title').textContent = __('Edit Listener'); document.getElementById('listener-id').value = id; document.getElementById('listener-name').value = name; document.getElementById('listener-scheme').value = scheme || 'http'; document.getElementById('listener-host').value = host; document.getElementById('listener-port').value = port; document.getElementById('listener-notes').value = notes || ''; document.getElementById('listener-enabled').checked = enabled; document.getElementById('listener-modal').classList.remove('hidden'); document.getElementById('listener-modal').classList.add('flex'); } function hideListenerModal() { const modal = document.getElementById('listener-modal'); modal.classList.remove('flex'); modal.classList.add('hidden'); } async function saveListener(btn) { const id = document.getElementById('listener-id').value; const scheme = document.getElementById('listener-scheme').value; const payload = { name: document.getElementById('listener-name').value, scheme: scheme, host: document.getElementById('listener-host').value, port: parseInt(document.getElementById('listener-port').value), notes: document.getElementById('listener-notes').value, enabled: document.getElementById('listener-enabled').checked }; if (scheme === 'http' || scheme === 'https') { payload.type = 'http'; payload.protocol = scheme; } else { payload.type = 'tcp'; payload.protocol = scheme; } const url = id ? `/api/listeners/${id}` : '/api/listeners'; const method = id ? 'PUT' : 'POST'; try { btn.disabled = true; const data = await apiFetch(url, {method, headers: {'Content-Type': 'application/json'}, body: JSON.stringify(payload)}); if (data.success) { hideListenerModal(); location.reload(); } else showToast(__tf('Save failed: {0}', data.error || __('Unknown error')), 'error'); } catch (e) { showToast(__tf('Save failed: {0}', e.message), 'error'); } finally { btn.disabled = false; } } function toggleListener(id, currentEnabled) { apiFetch(`/api/listeners/${id}`, {method: 'PUT', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ enabled: !currentEnabled })}) .then(() => location.reload()) .catch(e => showToast(__tf('Toggle failed: {0}', e.message), 'error')); } function deleteListener(id, name) { if (!confirm(__tf('Delete listener "{0}"?', name))) return; apiFetch(`/api/listeners/${id}`, {method: 'DELETE'}) .then(() => location.reload()) .catch(e => showToast(__tf('Delete failed: {0}', e.message), 'error')); } function copyConnect(url, name) { navigator.clipboard.writeText(url).then(() => { showToast(__tf('Copied {0} connection address', name), 'success'); }); } document.addEventListener('DOMContentLoaded', function() { if (new URLSearchParams(window.location.search).get('create') === '1') { showCreateModal(); } });

